use tower::{Service, ServiceBuilder, service_fn};
use std::time::Duration;

async fn handle(req: &str) -> Result<&str, ()> {
    Ok(req)
}

fn main() {
    let service = ServiceBuilder::new()
        .timeout(Duration::from_secs(5))
        .service(service_fn(handle));
}
